/// <summary>
/// Extension of the <c>InventJournalTable</c> table for the ETGSPAIN model.
/// </summary>
[ExtensionOf(tableStr(InventJournalTable))]
final class InventJournalTable_ETGSPAIN_Table_Extension
{
}

Method.Source:
/// <summary>
/// Validates the deletion of an <c>InventJournalTable</c> record.
/// </summary>
/// <returns>
/// Returns <c>true</c> if the record can be deleted; otherwise, <c>false</c>.
/// </returns>
public boolean validateDelete()
{
    boolean ret;

    ret = next validateDelete();

    ETGSPAINSalesPackingSlipImport etgSPAINSalesPackingSlipImport;

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        select firstonly etgSPAINSalesPackingSlipImport
        where etgSPAINSalesPackingSlipImport.InventJournalId == this.JournalId
        && etgSPAINSalesPackingSlipImport.Status == IFRUniversalInterfaceSystemStatus::Posted;

        if (etgSPAINSalesPackingSlipImport)
        {
            ret = false;
        }
    }

    return ret;
}
